using System.Text.RegularExpressions;
using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // ── FormatPhoneNumber ──────────────────────────────────────────

    [TestMethod]
    public void FormatPhoneNumber_ReturnsCorrectFormat()
    {
        var result = _formatter.FormatPhoneNumber("1234567890");

        Assert.AreEqual("(123) 456-7890", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_StartsWithAreaCodeInParens()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");

        StringAssert.StartsWith(result, "(800)");
    }

    [TestMethod]
    public void FormatPhoneNumber_EndsWithLastFourDigits()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");

        StringAssert.EndsWith(result, "1234");
    }

    [TestMethod]
    public void FormatPhoneNumber_ContainsDashSeparator()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");

        StringAssert.Contains(result, "-");
    }

    [TestMethod]
    public void FormatPhoneNumber_MatchesExpectedPattern()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");

        StringAssert.Matches(result, new Regex(@"^\(\d{3}\) \d{3}-\d{4}$"));
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentNullException))]
    public void FormatPhoneNumber_NullInput_Throws()
    {
        _formatter.FormatPhoneNumber(null!);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void FormatPhoneNumber_WrongLength_Throws()
    {
        _formatter.FormatPhoneNumber("123");
    }

    // ── BuildGreeting ──────────────────────────────────────────────

    [TestMethod]
    public void BuildGreeting_DefaultTitle_ReturnsCorrectGreeting()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.AreEqual("Dear Mr. Smith,", result);
    }

    [TestMethod]
    public void BuildGreeting_StartsWithDear()
    {
        var result = _formatter.BuildGreeting("Jones", "Dr.");

        StringAssert.StartsWith(result, "Dear");
    }

    [TestMethod]
    public void BuildGreeting_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Jones", "Dr.");

        StringAssert.EndsWith(result, ",");
    }

    [TestMethod]
    public void BuildGreeting_ContainsName()
    {
        var result = _formatter.BuildGreeting("Gonzalez", "Ms.");

        StringAssert.Contains(result, "Gonzalez");
    }

    [TestMethod]
    public void BuildGreeting_CustomTitle()
    {
        var result = _formatter.BuildGreeting("Curie", "Prof.");

        Assert.AreEqual("Dear Prof. Curie,", result);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void BuildGreeting_WhitespaceName_Throws()
    {
        _formatter.BuildGreeting("   ");
    }

    // ── GenerateSlug ───────────────────────────────────────────────

    [TestMethod]
    public void GenerateSlug_BasicTitle_ReturnsLowercaseDashed()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_DoesNotStartWithDash()
    {
        var result = _formatter.GenerateSlug("  --Hello World--  ");

        StringAssert.DoesNotMatch(result, new Regex("^-"));
    }

    [TestMethod]
    public void GenerateSlug_DoesNotEndWithDash()
    {
        var result = _formatter.GenerateSlug("  --Hello World--  ");

        StringAssert.DoesNotMatch(result, new Regex("-$"));
    }

    [TestMethod]
    public void GenerateSlug_SpecialCharsCollapsedToDash()
    {
        var result = _formatter.GenerateSlug("C# is @awesome!!");

        Assert.AreEqual("c-is-awesome", result);
    }

    [TestMethod]
    public void GenerateSlug_MatchesSlugPattern()
    {
        var result = _formatter.GenerateSlug("My Article Title 2024");

        StringAssert.Matches(result, new Regex(@"^[a-z0-9]+(-[a-z0-9]+)*$"));
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void GenerateSlug_WhitespaceInput_Throws()
    {
        _formatter.GenerateSlug("   ");
    }

    // ── FormatCurrency ─────────────────────────────────────────────

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWith_Dollar()
    {
        var result = _formatter.FormatCurrency(9.99m);

        StringAssert.StartsWith(result, "$");
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWith_Euro()
    {
        var result = _formatter.FormatCurrency(19.99m, "€");

        StringAssert.StartsWith(result, "€");
    }

    [TestMethod]
    public void FormatCurrency_AlwaysShowsTwoDecimalPlaces()
    {
        var result = _formatter.FormatCurrency(5m);

        StringAssert.EndsWith(result, ".00");
    }

    [TestMethod]
    public void FormatCurrency_RoundsToTwoDecimals()
    {
        var result = _formatter.FormatCurrency(1.999m);

        Assert.AreEqual("$2.00", result);
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount()
    {
        var result = _formatter.FormatCurrency(-42.50m);

        StringAssert.Contains(result, "-");
        StringAssert.EndsWith(result, "42.50");
    }
}

